const patterns = $('Analyze Page Patterns').first().json.patterns;
const stories = $('List All Pages').first().json.stories;

const issues = [];
for (const story of stories) {
  const content = story.content;
  if (!content || !content.section) continue;
  const sections = Array.isArray(content.section) ? content.section : [];

  // Check for missing CTA
  const hasCta = sections.some(s => {
    if (!Array.isArray(s.components)) return false;
    return s.components.some(c => c.component === 'cta');
  });
  const hasHero = sections.some(s => {
    if (!Array.isArray(s.components)) return false;
    return s.components.some(c => c.component === 'hero');
  });
  const hasFeatures = sections.some(s => {
    if (!Array.isArray(s.components)) return false;
    return s.components.some(c => c.component === 'features' || c.component === 'split');
  });
  if (!hasCta && hasHero && hasFeatures && sections.length > 2) {
    issues.push({ story: story.full_slug, issue: 'Missing CTA section on conversion page', severity: 'warning', category: 'composition' });
  }

  // Check for sparse pages
  if (sections.length < 2) {
    issues.push({ story: story.full_slug, issue: `Only ${sections.length} section(s)`, severity: 'warning', category: 'content' });
  }

  // Check for duplicate heroes
  let heroCount = 0;
  for (const s of sections) {
    if (Array.isArray(s.components)) {
      heroCount += s.components.filter(c => c.component === 'hero' || c.component === 'video-curtain').length;
    }
  }
  if (heroCount > 1) {
    issues.push({ story: story.full_slug, issue: `${heroCount} hero sections (should be 1)`, severity: 'error', category: 'composition' });
  }

  // Check for adjacent same-type sections
  const sectionTypes = sections.map(s => {
    if (Array.isArray(s.components) && s.components.length > 0) return s.components[0].component;
    return null;
  }).filter(Boolean);
  for (let i = 1; i < sectionTypes.length; i++) {
    if (sectionTypes[i] === sectionTypes[i-1] && sectionTypes[i] !== 'divider') {
      issues.push({ story: story.full_slug, issue: `Adjacent "${sectionTypes[i]}" sections — may look repetitive`, severity: 'info', category: 'composition' });
    }
  }

  // Check for sparse sub-items
  const subItemMins = { stats: 3, features: 2, testimonials: 2, slider: 3, 'logos-companies': 4, mosaic: 3, gallery: 3 };
  for (const s of sections) {
    if (!Array.isArray(s.components)) continue;
    for (const comp of s.components) {
      const type = comp.component;
      if (!type || !subItemMins[type]) continue;
      const subKeys = Object.keys(comp).filter(k => Array.isArray(comp[k]) && comp[k].length > 0 && typeof comp[k][0] === 'object' && comp[k][0].component);
      for (const key of subKeys) {
        if (comp[key].length < subItemMins[type]) {
          issues.push({ story: story.full_slug, issue: `"${type}" has only ${comp[key].length} sub-items (min: ${subItemMins[type]})`, severity: 'warning', category: 'composition' });
        }
      }
    }
  }
}

return [{
  json: {
    totalPages: stories.length,
    totalIssues: issues.length,
    componentFrequency: patterns.componentFrequency,
    pageArchetypes: patterns.pageArchetypes,
    issues,
    compositionIssues: issues.filter(i => i.category === 'composition').length,
    contentIssues: issues.filter(i => i.category === 'content').length
  }
}];

